import org.junit.jupiter.api.Test;
import static org.junit.jupiter.api.Assertions.*;
import java.util.*;

public class SolutionTest {

    @Test
    void basic() {
        int[][] input = {{12, 500}, {15, 300}, {12, 200}, {15, 100}};
        Map<Integer, List<Integer>> result = new Solution().transactionsByDay(input);
        assertEquals(Set.of(12, 15), result.keySet());
        assertEquals(List.of(500, 200), result.get(12));
        assertEquals(List.of(300, 100), result.get(15));
    }

    @Test
    void empty() {
        Map<Integer, List<Integer>> result = new Solution().transactionsByDay(new int[][]{});
        assertTrue(result.isEmpty());
    }

    @Test
    void singleTransaction() {
        int[][] input = {{42, 9999}};
        Map<Integer, List<Integer>> result = new Solution().transactionsByDay(input);
        assertEquals(Set.of(42), result.keySet());
        assertEquals(List.of(9999), result.get(42));
    }

    @Test
    void allSameDay() {
        // adversarial: every transaction on the same day
        int[][] input = {{1, 100}, {1, 200}, {1, 300}, {1, 400}};
        Map<Integer, List<Integer>> result = new Solution().transactionsByDay(input);
        assertEquals(Set.of(1), result.keySet());
        assertEquals(List.of(100, 200, 300, 400), result.get(1));
    }

    @Test
    void eachDayDistinct() {
        // each transaction is on a different day — each bucket has exactly one amount
        int[][] input = {{10, 50}, {20, 75}, {30, 25}};
        Map<Integer, List<Integer>> result = new Solution().transactionsByDay(input);
        assertEquals(Set.of(10, 20, 30), result.keySet());
        assertEquals(List.of(50), result.get(10));
        assertEquals(List.of(75), result.get(20));
        assertEquals(List.of(25), result.get(30));
    }

    @Test
    void preservesAmountOrder() {
        // amounts for the same day must appear in input order
        int[][] input = {{7, 1000}, {7, 2000}, {7, 500}};
        Map<Integer, List<Integer>> result = new Solution().transactionsByDay(input);
        assertEquals(List.of(1000, 2000, 500), result.get(7));
    }

    @Test
    void zeroCentTransaction() {
        // zero-cent transactions are valid and must be included
        int[][] input = {{5, 0}, {5, 100}};
        Map<Integer, List<Integer>> result = new Solution().transactionsByDay(input);
        assertEquals(List.of(0, 100), result.get(5));
    }
}
